-- ========================================================\n-- 订单状态管理流程优化 - 数据库变更脚本\n-- 创建时间: 2026-03-21\n-- ========================================================\n\n-- --------------------------------------------------------\n-- 步骤1.1: 扩展orders表字段\n-- --------------------------------------------------------\n\n-- 费用相关字段\nALTER TABLE orders \nADD COLUMN rental_days INT DEFAULT NULL COMMENT '租车天数' AFTER end_time,\nADD COLUMN daily_rate DECIMAL(10,2) DEFAULT NULL COMMENT '日租金' AFTER rental_days,\nADD COLUMN rental_fee DECIMAL(10,2) DEFAULT NULL COMMENT '租金费用' AFTER daily_rate,\nADD COLUMN insurance_fee DECIMAL(10,2) DEFAULT 0 COMMENT '保险费用' AFTER rental_fee,\nADD COLUMN service_fee DECIMAL(10,2) DEFAULT 0 COMMENT '服务费用' AFTER insurance_fee,\nADD COLUMN overtime_fee DECIMAL(10,2) DEFAULT 0 COMMENT '超时费用' AFTER service_fee,\nADD COLUMN mileage_fee DECIMAL(10,2) DEFAULT 0 COMMENT '超里程费用' AFTER overtime_fee,\nADD COLUMN discount_amount DECIMAL(10,2) DEFAULT 0 COMMENT '优惠金额' AFTER mileage_fee;\n\n-- 时间记录字段\nALTER TABLE orders \nADD COLUMN pay_time DATETIME DEFAULT NULL COMMENT '支付时间' AFTER update_time,\nADD COLUMN confirm_time DATETIME DEFAULT NULL COMMENT '确认时间' AFTER pay_time,\nADD COLUMN cancel_time DATETIME DEFAULT NULL COMMENT '取消时间' AFTER confirm_time;\n\n-- 取消信息字段\nALTER TABLE orders \nADD COLUMN cancel_reason VARCHAR(500) DEFAULT NULL COMMENT '取消原因' AFTER cancel_time,\nADD COLUMN cancel_by VARCHAR(50) DEFAULT NULL COMMENT '取消人' AFTER cancel_reason,\nADD COLUMN cancel_reason_code VARCHAR(50) DEFAULT NULL COMMENT '取消原因编码' AFTER cancel_by;\n\n-- 车辆检查字段\nALTER TABLE orders \nADD COLUMN mileage_out INT DEFAULT NULL COMMENT '取车里程' AFTER return_remark,\nADD COLUMN mileage_in INT DEFAULT NULL COMMENT '还车里程' AFTER mileage_out,\nADD COLUMN fuel_level_out TINYINT DEFAULT NULL COMMENT '取车油量(百分比)' AFTER mileage_in,\nADD COLUMN fuel_level_in TINYINT DEFAULT NULL COMMENT '还车油量(百分比)' AFTER fuel_level_out,\nADD COLUMN damage_description VARCHAR(1000) DEFAULT NULL COMMENT '车辆损伤描述' AFTER fuel_level_in,\nADD COLUMN damage_photos TEXT DEFAULT NULL COMMENT '损伤照片JSON数组' AFTER damage_description;\n\n-- 结算字段\nALTER TABLE orders \nADD COLUMN settlement_amount DECIMAL(10,2) DEFAULT NULL COMMENT '结算金额' AFTER damage_photos,\nADD COLUMN settlement_time DATETIME DEFAULT NULL COMMENT '结算时间' AFTER settlement_amount,\nADD COLUMN settlement_by VARCHAR(50) DEFAULT NULL COMMENT '结算人' AFTER settlement_time;\n\n-- 添加索引\nCREATE INDEX idx_pay_time ON orders(pay_time);\nCREATE INDEX idx_confirm_time ON orders(confirm_time);\nCREATE INDEX idx_cancel_time ON orders(cancel_time);\nCREATE INDEX idx_settlement_time ON orders(settlement_time);\n\n-- --------------------------------------------------------\n-- 步骤1.2: 创建车辆检查记录表\n-- --------------------------------------------------------\nCREATE TABLE IF NOT EXISTS order_car_checks (\n    id BIGINT PRIMARY KEY AUTO_INCREMENT COMMENT '主键ID',\n    order_id BIGINT NOT NULL COMMENT '订单ID',\n    check_type TINYINT NOT NULL COMMENT '检查类型：1-取车检查，2-还车检查',\n    check_item VARCHAR(100) NOT NULL COMMENT '检查项目',\n    check_result TINYINT NOT NULL DEFAULT 1 COMMENT '检查结果：0-异常，1-正常',\n    description VARCHAR(500) DEFAULT NULL COMMENT '问题描述',\n    photos TEXT DEFAULT NULL COMMENT '照片JSON数组',\n    checked_by VARCHAR(50) DEFAULT NULL COMMENT '检查人',\n    checked_time DATETIME DEFAULT CURRENT_TIMESTAMP COMMENT '检查时间',\n    remark VARCHAR(500) DEFAULT NULL COMMENT '备注',\n    create_time DATETIME DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',\n    update_time DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',\n    KEY idx_order_id (order_id),\n    KEY idx_check_type (check_type),\n    KEY idx_checked_time (checked_time)\n) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='订单车辆检查记录表';\n\n-- --------------------------------------------------------\n-- 步骤1.3: 创建取消原因分类表\n-- --------------------------------------------------------\nCREATE TABLE IF NOT EXISTS cancel_reasons (\n    id BIGINT PRIMARY KEY AUTO_INCREMENT COMMENT '主键ID',\n    reason_code VARCHAR(50) NOT NULL COMMENT '原因编码',\n    reason_name VARCHAR(100) NOT NULL COMMENT '原因名称',\n    reason_type TINYINT NOT NULL COMMENT '类型：1-用户取消，2-系统取消，3-管理员取消',\n    sort_order INT DEFAULT 0 COMMENT '排序',\n    is_active TINYINT DEFAULT 1 COMMENT '是否启用：0-禁用，1-启用',\n    create_time DATETIME DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',\n    update_time DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',\n    UNIQUE KEY uk_reason_code (reason_code),\n    KEY idx_reason_type (reason_type),\n    KEY idx_sort_order (sort_order)\n) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='取消原因分类表';\n\n-- 初始化取消原因数据\nINSERT INTO cancel_reasons (reason_code, reason_name, reason_type, sort_order) VALUES\n('USER_CHANGE_PLAN', '用户改变行程计划', 1, 1),\n('USER_FIND_BETTER', '用户找到更优惠的价格', 1, 2),\n('USER_NO_LICENSE', '用户无法提供有效驾照', 1, 3),\n('USER_OTHER', '用户其他原因', 1, 99),\n('SYS_NO_PAY', '超时未支付', 2, 1),\n('SYS_CAR_UNAVAILABLE', '车辆不可用', 2, 2),\n('ADMIN_FRAUD', '发现欺诈行为', 3, 1),\n('ADMIN_VIOLATION', '违反租赁条款', 3, 2),\n('ADMIN_OTHER', '管理员其他原因', 3, 99)\nON DUPLICATE KEY UPDATE \nreason_name = VALUES(reason_name), \nreason_type = VALUES(reason_type), \nsort_order = VALUES(sort_order);\n\n-- --------------------------------------------------------\n-- 数据迁移：更新现有订单数据\n-- --------------------------------------------------------\n\n-- 更新租车天数\nUPDATE orders \nSET rental_days = DATEDIFF(end_time, start_time) \nWHERE rental_days IS NULL AND start_time IS NOT NULL AND end_time IS NOT NULL;\n\n-- 更新日租金和租金费用（从车辆信息计算）\nUPDATE orders o\nJOIN cars c ON o.car_id = c.id\nSET o.daily_rate = c.price_per_day,\n    o.rental_fee = c.price_per_day * DATEDIFF(o.end_time, o.start_time)\nWHERE o.daily_rate IS NULL AND o.car_id IS NOT NULL;\n